import{_ as n,o as s,c as t,ae as e}from"./chunks/framework.B6gjLfeO.js";const d=JSON.parse('{"title":"1세대: 프롬프트 엔지니어링","description":"","frontmatter":{},"headers":[],"relativePath":"part2-evolution/prompt-engineering.md","filePath":"part2-evolution/prompt-engineering.md"}'),o={name:"part2-evolution/prompt-engineering.md"};function i(p,a,l,r,h,c){return s(),t("div",null,[...a[0]||(a[0]=[e(`<h1 id="_1세대-프롬프트-엔지니어링" tabindex="-1">1세대: 프롬프트 엔지니어링 <a class="header-anchor" href="#_1세대-프롬프트-엔지니어링" aria-label="Permalink to &quot;1세대: 프롬프트 엔지니어링&quot;">​</a></h1><blockquote><p><strong>스토리</strong>: &quot;마법의 주문을 외우던 시절&quot;</p></blockquote><h2 id="정의" tabindex="-1">정의 <a class="header-anchor" href="#정의" aria-label="Permalink to &quot;정의&quot;">​</a></h2><p><strong>프롬프트 엔지니어링(Prompt Engineering)</strong>이란, AI에게 최적의 결과를 얻기 위해 <strong>입력(프롬프트)을 정교하게 설계하는 기술</strong>입니다.</p><p>같은 질문이라도 <strong>어떻게 물어보느냐</strong>에 따라 결과가 극적으로 달라집니다.</p><h2 id="핵심-기법" tabindex="-1">핵심 기법 <a class="header-anchor" href="#핵심-기법" aria-label="Permalink to &quot;핵심 기법&quot;">​</a></h2><h3 id="_1-few-shot-프롬프팅" tabindex="-1">1. Few-shot 프롬프팅 <a class="header-anchor" href="#_1-few-shot-프롬프팅" aria-label="Permalink to &quot;1. Few-shot 프롬프팅&quot;">​</a></h3><p>AI에게 <strong>예시를 먼저 보여주고</strong> 패턴을 따르게 하는 방법입니다.</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>❌ 나쁜 예</span></span>
<span class="line"><span>&quot;버튼 컴포넌트 만들어줘&quot;</span></span>
<span class="line"><span></span></span>
<span class="line"><span>✅ 좋은 예</span></span>
<span class="line"><span>&quot;아래 형식으로 버튼 컴포넌트를 만들어줘:</span></span>
<span class="line"><span>  </span></span>
<span class="line"><span> 예시)</span></span>
<span class="line"><span> &lt;Button variant=&quot;primary&quot; size=&quot;lg&quot;&gt;저장&lt;/Button&gt;</span></span>
<span class="line"><span> &lt;Button variant=&quot;outline&quot; size=&quot;sm&quot;&gt;취소&lt;/Button&gt;</span></span>
<span class="line"><span>  </span></span>
<span class="line"><span> 이 패턴으로 &#39;danger&#39; variant를 추가해줘&quot;</span></span></code></pre></div><h3 id="_2-chain-of-thought-단계별-사고" tabindex="-1">2. Chain-of-Thought (단계별 사고) <a class="header-anchor" href="#_2-chain-of-thought-단계별-사고" aria-label="Permalink to &quot;2. Chain-of-Thought (단계별 사고)&quot;">​</a></h3><p>AI에게 <strong>사고 과정을 단계별로 밟도록</strong> 유도합니다.</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>&quot;TODO 앱의 인증 로직을 설계해줘.</span></span>
<span class="line"><span> 1단계: 필요한 API 엔드포인트를 나열하고</span></span>
<span class="line"><span> 2단계: 각 엔드포인트의 요청/응답 스키마를 정의하고</span></span>
<span class="line"><span> 3단계: 에러 핸들링 전략을 수립해줘&quot;</span></span></code></pre></div><h3 id="_3-role-프롬프팅" tabindex="-1">3. Role 프롬프팅 <a class="header-anchor" href="#_3-role-프롬프팅" aria-label="Permalink to &quot;3. Role 프롬프팅&quot;">​</a></h3><p>AI에게 <strong>역할을 부여</strong>합니다.</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>&quot;너는 10년 경력의 시니어 풀스택 개발자야.</span></span>
<span class="line"><span> 보안에 특히 신경 쓰고, 코드 리뷰를 철저히 해.&quot;</span></span></code></pre></div><h2 id="한계점" tabindex="-1">한계점 <a class="header-anchor" href="#한계점" aria-label="Permalink to &quot;한계점&quot;">​</a></h2><div class="warning custom-block"><p class="custom-block-title">⚠️ 프롬프트 엔지니어링의 구조적 한계</p><h3 id="_1-컨텍스트-윈도우-한계" tabindex="-1">1. 컨텍스트 윈도우 한계 <a class="header-anchor" href="#_1-컨텍스트-윈도우-한계" aria-label="Permalink to &quot;1. 컨텍스트 윈도우 한계&quot;">​</a></h3><p>AI의 기억력에는 한계가 있습니다(토큰 수). 대화가 길어지면 초반 내용을 <strong>까먹습니다</strong>.</p><h3 id="_2-매번-반복-설명" tabindex="-1">2. 매번 반복 설명 <a class="header-anchor" href="#_2-매번-반복-설명" aria-label="Permalink to &quot;2. 매번 반복 설명&quot;">​</a></h3><p>&quot;React를 쓰고 있고, TypeScript고, Tailwind를 쓰고…&quot; 매번 같은 맥락을 반복해야 합니다.</p><h3 id="_3-대규모-프로젝트-불가" tabindex="-1">3. 대규모 프로젝트 불가 <a class="header-anchor" href="#_3-대규모-프로젝트-불가" aria-label="Permalink to &quot;3. 대규모 프로젝트 불가&quot;">​</a></h3><p>파일이 100개가 넘는 프로젝트에서는, 프롬프트만으로 전체 맥락을 전달할 수 없습니다.</p><h3 id="_4-결과의-비일관성" tabindex="-1">4. 결과의 비일관성 <a class="header-anchor" href="#_4-결과의-비일관성" aria-label="Permalink to &quot;4. 결과의 비일관성&quot;">​</a></h3><p>같은 프롬프트라도 실행할 때마다 <strong>다른 스타일의 코드</strong>가 나옵니다.</p></div><h2 id="비유로-이해하기" tabindex="-1">비유로 이해하기 <a class="header-anchor" href="#비유로-이해하기" aria-label="Permalink to &quot;비유로 이해하기&quot;">​</a></h2><p>프롬프트 엔지니어링은 마치 <strong>외국어를 잘 못하는 프리랜서</strong>에게 일을 맡기는 것과 같습니다:</p><ul><li>✅ 잘 설명하면 잘 해줌</li><li>❌ 설명이 부족하면 엉뚱한 결과</li><li>❌ 지난번에 설명한 건 기억 못 함</li><li>❌ 매번 처음부터 다시 설명해야 함</li></ul><blockquote><p><em>&quot;더 잘 설명하는 것만으로는 한계가 있다. AI에게 기억을 줘야 한다.&quot;</em></p><p>→ 이것이 <strong>2세대: 컨텍스트 엔지니어링</strong>의 출발점입니다.</p></blockquote>`,21)])])}const g=n(o,[["render",i]]);export{d as __pageData,g as default};
